  "inlineSchema": "// ============================================================\n//  Esquema do banco — Escola de Capacitação (Cruz Vermelha RJ)\n//  Banco: PostgreSQL  |  ORM: Prisma\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ---------- Enums ----------\n\nenum Papel {\n  ALUNO\n  SECRETARIA\n}\n\nenum StatusTurma {\n  ABERTA\n  CONFIRMADA\n  CANCELADA\n  ENCERRADA\n}\n\nenum PlanoPagamento {\n  A_VISTA // pagamento único, com desconto\n  PARCELADO // preço cheio dividido em parcelas\n}\n\nenum FormaPagamento {\n  PIX\n  DEBITO\n  CREDITO\n  DINHEIRO // presencial, confirmado manualmente pela secretaria\n}\n\nenum StatusPagamento {\n  PENDENTE\n  PAGO\n  CANCELADO\n  ESTORNADO\n}\n\n// ---------- Usuário ----------\n// O cadastro público SEMPRE cria papel = ALUNO.\n// Conta SECRETARIA é criada via seed/painel admin, nunca pelo formulário público.\n\nmodel Usuario {\n  id                  String      @id @default(uuid())\n  nome                String\n  email               String      @unique\n  cpfCnpj             String?     @unique // só dígitos; nulo p/ contas antigas/seed\n  senhaHash           String\n  papel               Papel       @default(ALUNO)\n  emailVerificado     Boolean     @default(false)\n  // LGPD: registramos QUANDO consentiu e QUAL versão da política aceitou\n  consentimentoLgpdEm DateTime?\n  consentimentoVersao String?\n  criadoEm            DateTime    @default(now())\n  atualizadoEm        DateTime    @updatedAt\n  matriculas          Matricula[]\n}\n\n// ---------- Catálogo de cursos ----------\n\nmodel Curso {\n  id                 String   @id @default(uuid())\n  nome               String\n  descricao          String?\n  cargaHoraria       Int // em horas\n  escolaridadeMinima String?\n  imagemUrl          String? // foto do card (placeholder por ora; trocar por foto real)\n  precoAvista        Decimal  @db.Decimal(10, 2) // preço com desconto à vista\n  precoCheio         Decimal  @db.Decimal(10, 2) // preço cheio (base do parcelamento)\n  parcelas           Int      @default(1)\n  valorParcela       Decimal  @db.Decimal(10, 2)\n  // Taxa de matrícula POR CURSO. Se null, usa o padrão global (tabela Configuracao).\n  // Defina 0 para um curso sem taxa. Veja \"matricula_modo\" no README.\n  taxaMatricula      Decimal? @db.Decimal(10, 2)\n  ativo              Boolean  @default(true)\n  criadoEm           DateTime @default(now())\n  turmas             Turma[]\n}\n\n// ---------- Turma (oferta concreta de um curso, com datas) ----------\n\nmodel Turma {\n  id             String      @id @default(uuid())\n  curso          Curso       @relation(fields: [cursoId], references: [id])\n  cursoId        String\n  inicioPrevisto DateTime\n  fimPrevisto    DateTime?\n  horario        String // ex.: \"18:00-22:00\"\n  diasSemana     String // ex.: \"Terças e Quintas\"\n  vagas          Int         @default(30)\n  minimoAlunos   Int         @default(15)\n  status         StatusTurma @default(ABERTA)\n  criadoEm       DateTime    @default(now())\n  matriculas     Matricula[]\n}\n\n// ---------- Matrícula (aluno em uma turma) ----------\n\nmodel Matricula {\n  id                 String          @id @default(uuid())\n  aluno              Usuario         @relation(fields: [alunoId], references: [id])\n  alunoId            String\n  turma              Turma           @relation(fields: [turmaId], references: [id])\n  turmaId            String\n  plano              PlanoPagamento\n  forma              FormaPagamento\n  // \"Fotografamos\" os valores no momento da matrícula (preço pode mudar depois)\n  valorCurso         Decimal         @db.Decimal(10, 2)\n  valorTaxaMatricula Decimal         @default(0) @db.Decimal(10, 2)\n  alimentoEntregue   Boolean         @default(false) // 1kg de alimento não perecível\n  statusPagamento    StatusPagamento @default(PENDENTE)\n  // Preenchidos quando a secretaria confirma um pagamento presencial\n  confirmadaPor      String?\n  confirmadaEm       DateTime?\n  criadoEm           DateTime        @default(now())\n  atualizadoEm       DateTime        @updatedAt\n  pagamentos         Pagamento[]\n\n  @@unique([alunoId, turmaId]) // um aluno não matricula duas vezes na mesma turma\n}\n\n// ---------- Pagamento ----------\n// Cartão/Pix: criado e confirmado via gateway (webhook). Dinheiro: confirmação manual.\n// O número do cartão NUNCA passa por aqui — fica só no checkout do gateway.\n\nmodel Pagamento {\n  id           String          @id @default(uuid())\n  matricula    Matricula       @relation(fields: [matriculaId], references: [id])\n  matriculaId  String\n  gateway      String? // ex.: \"mercadopago\" (null se presencial)\n  gatewayRef   String? // id da transação no gateway, para conciliar com o webhook\n  metodo       FormaPagamento\n  valor        Decimal         @db.Decimal(10, 2)\n  status       StatusPagamento @default(PENDENTE)\n  criadoEm     DateTime        @default(now())\n  atualizadoEm DateTime        @updatedAt\n}\n\n// ---------- Tokens (verificação de e-mail / recuperação de senha) ----------\n// Guardamos o HASH do token, nunca o token em claro. Uso único e com expiração.\n\nmodel TokenAuth {\n  id        String    @id @default(uuid())\n  usuarioId String\n  tipo      String // \"VERIFICACAO_EMAIL\" | \"RESET_SENHA\"\n  tokenHash String\n  expiraEm  DateTime\n  usadoEm   DateTime?\n  criadoEm  DateTime  @default(now())\n}\n\n// ---------- Configurações (chave/valor) ----------\n// Aqui mora a flexibilidade da taxa de matrícula:\n//   matricula_modo         = \"POR_CURSO\" | \"POR_ALUNO\" | \"NENHUMA\"\n//   matricula_valor_padrao = \"100.00\"\n// Trocar para \"NENHUMA\" (ou zerar) remove a taxa sem mexer no código.\n\nmodel Configuracao {\n  chave String @id\n  valor String\n}\n\n// ---------- Log de auditoria (ações da secretaria) ----------\n\nmodel LogAuditoria {\n  id       String   @id @default(uuid())\n  atorId   String // id da secretaria que executou a ação\n  acao     String // ex.: \"CONFIRMOU_PAGAMENTO\"\n  alvoTipo String // ex.: \"Matricula\"\n  alvoId   String?\n  detalhe  Json?\n  criadoEm DateTime @default(now())\n}\n",
